693→        if (empty($sfuserId)) {
694→            return false;
695→        }
696→        $files = (array)Arr::get($input, 'files', []);
697→        $content = Arr::get($input, 'content', '');
698→        // ccUser直接取抄送表里的, (多站点问题)
699→        $ccUser = DailyReportCC::where('sfuser_id', $sfuserId)->pluck('cc_id')->toArray();
700→        /** @var null|Sfuser $user */
701→        $user = Sfuser::where('id', $sfuserId)->first();
702→        if (empty($user)) {
703→            return false;
704→        }
705→        $ceoId = 171514;
706→        if (!App::environment('production')) { // 测试服
707→            $ceoId = 145908;
708→        } elseif (str_starts_with(config('app.name'), 'OA_STAGING')) { // 预发布
709→            $ceoId = 799007;
710→        }
711→        $reportUser = [];
712→        if ($user->direct_supervisor_id) {
713→            $reportUser[] = $user->direct_supervisor_id;
714→        }
715→        if ($user->supervisor_id) {
716→            $reportUser[] = $user->supervisor_id;
717→        }
718→        $reportUser[] = $ceoId;
719→        $reportUser = array_unique($reportUser);
720→        $date = $input['report_date'] ?? date('Y-m-d');
721→        if ($date > date('Y-m-d')) {
722→            return false;
723→        }
724→        $isLate = $input['is_late'] ?? 0;
725→        $data = (array)Arr::get($input, 'data', []);
726→        $token = $input['authorized_token'] ?? '';
727→        $status = Arr::get($input, 'status', 0);
728→        $reportUserString = implode(',', $reportUser);
729→        $ccUserString = implode(',', $ccUser);
730→
731→        $calendarId = $this->getCalendarIdByDate($date);
732→        $dailyReport = DailyReport::where('sfuser_id', $sfuserId)->where('calendar_id', $calendarId)->first();
733→        if (empty($dailyReport)) {
734→            $dailyReport = new DailyReport();
735→            $dailyReport->sfuser_id = $sfuserId;
736→            $dailyReport->calendar_id = $calendarId;
737→            $dailyReport->is_late = $isLate;
738→        }
739→        $oldStatus = $dailyReport->status ?? DailyReport::STATUS_DRAFT;
740→        $dailyReport->reporter_ids = $reportUserString;
741→        $dailyReport->cc_ids = $ccUserString;
742→        $dailyReport->content = $content;
743→        $dailyReport->files = $files;
744→        $dailyReport->data = $data;
745→        $dailyReport->token = $token;
746→        $dailyReport->report_date = $date;
747→        if ($status == DailyReport::STATUS_COMMITTED) {
748→            $dailyReport->status = DailyReport::STATUS_COMMITTED;
749→        } else {
750→            $status = $oldStatus;
751→            $dailyReport->status = $oldStatus;
752→        }
753→        if (!$dailyReport->save()) {
754→            return false;
755→        }
756→        // 提交日报
757→        if ($status == DailyReport::STATUS_COMMITTED) {
758→            $this->setDailyReportCache($sfuserId, $calendarId, $date);
759→            $dailyReportId = $dailyReport->id;
760→            $newReportId = array_unique(array_values(array_merge($reportUser, $ccUser)));
761→            // 获取之前的
762→            $startDate = date('Y-m-d', strtotime('- 60 days'));
763→            $endDate = date('Y-m-d');
764→            $beforeReportIds = DailyReportRead::where('cdate', '>=', $startDate)->where('cdate', '<=', $endDate)->where('sfuser_id', $sfuserId)->where('daily_report_id', $dailyReportId)->pluck('receiver_id')->toArray();
765→            $deleteReportIds = array_values(array_diff($beforeReportIds, $newReportId));
766→            if ($deleteReportIds) {
