210→     *
211→     * @codeCoverageIgnored
212→     *
213→     * @param string $url
214→     * @param mixed $data
215→     * @param array $options
216→     * @param array $guzzle_options
217→     * @param string $contentType
218→     * @param array $header
219→     * @param bool $return_header
220→     *
221→     * @throws \GuzzleHttp\Exception\GuzzleException
222→     * @return string
223→     */
224→    protected function execGuzzle(
225→        string $url,
226→        $data = [],
227→        $options = [],
228→        $guzzle_options = [],
229→        $contentType = 'json',
230→        array $header = [],
231→        bool $return_header = false
232→    ): string {
233→        $methodName = 'GET';
234→        $requestData = [];
235→        if (!empty($data)) {
236→            $methodName = 'POST';
237→            $requestData[$contentType] = $data;
238→        }
239→        if (!empty($guzzle_options)) {
240→            $requestData = array_merge($requestData, $guzzle_options);
241→        }
242→
243→        if (!empty($header)) {
244→            $requestData['headers'] = $header;
245→        }
246→        $response = MyGuzzle::client($options)->request($methodName, $url, $requestData);
247→        $res = $response->getBody();
