285→    {
286→        if (!isset($response['error_code']) && isset($response['error'])) {
287→            $error_code = $response['error'];
288→            $error_msg = $response['error_description'];
289→            unset($response['error'], $response['error_description']);
290→
291→            $data = $response;
292→            $response = compact('error_code', 'error_msg', 'data');
293→        }
294→
295→        if (!isset($response['error_code'])) {
296→            throw new RemoteException(__('my_api.api_res_error').substr(json_encode($response), 0, static::RES_ERR_SHOW_LEN), 803);
297→        }
298→
299→        $response['error_code'] = (string)(
300→            is_numeric($response['error_code']) ? $response['error_code'] : Code::ERR_REMOTE
301→        );
302→
303→        if ($response['error_code'] !== '0') {
304→            if ($response['error_code'] == Code::ERR_USER) {
