326→                imgs.forEach((item, index) => {
327→                    const src = item.match(/src="(.+)"/)
328→
329→                    if (src && src[1].split(':')[0] === 'data') {
330→                        const blob = src[1]
331→                        base64Info.push({
332→                            fileFormat: blob.split(',')[0].split(':')[1].split(';')[0].split('/')[1],
333→                            blob: blob,
334→                            imgIndex: index,
335→                        })
336→                    }
337→                })
338→
339→                for (const element of base64Info) {
340→                    const blobInfo = base64toBlob(element.blob)
341→                    const file = this.blobToFile(blobInfo, Date.now() + '.' + element.fileFormat)
342→
343→                    const newUrl = URL.createObjectURL(file)
344→                    this.needRevokeUrlFiles.push({
345→                        url: newUrl,
346→                        file: file,
347→                    })
348→                    // base64替换为URL, 方便后续进行src替换
349→                    imgs.splice(element.imgIndex, 1, `<img src="${newUrl}"/>`)
350→                }
351→                for (let i = imgs.length - 1; i >= 0; i--) {
352→                    textContentArr.splice(i + 1, 0, imgs[i])
