440→    async getReportContent(replaceBase64) {
441→        try {
442→            let editorData = this.editor.txt.html()
443→            if (replaceBase64) {
444→                for (let i = 0; i < this.needRevokeUrlFiles.length; i++) {
445→                    const reg = new RegExp(this.needRevokeUrlFiles[i].url)
446→
447→                    if (reg.test(editorData)) {
448→                        await this.uploadFile(this.needRevokeUrlFiles[i].file, url => {
449→                            // 将base64图片上传转化为url形式
450→                            editorData = editorData.replace(reg, url)
451→                        })
452→                    }
453→
454→                    URL.revokeObjectURL(this.needRevokeUrlFiles[i].url)
455→                }
456→            }
457→            editorData = editorData.replace(/\s+/g, '&nbsp;')
458→            const arr = editorData.split('&nbsp;')
459→            editorData = _.difference(arr, ['']).join(' ')
460→
461→            const arr2 = editorData.split('<br/>')
462→            editorData = _.difference(arr2, ['']).join('<br/>')
463→            // 去除外有元素包裹的连续空行
464→            editorData = this.deleteBrEle(editorData)
465→            return editorData
466→        } catch (e) {
467→            this.$message.error(e)
468→            return Promise.reject(e)
469→        }
470→    }
