475→        const timeNow = moment().format('HH:mm:ss')
476→        if (moment(attendanceDate + ' ' + timeNow).isBefore(attendanceDate + ' 06:00:00', 'second')) {
477→            attendanceDate = moment(attendanceDate).subtract(1, 'd').format('YYYY-MM-DD')
478→        }
479→        return attendanceDate !== this.editDate ? 1 : 0
480→    }
