 1→import axios from 'axios'
 2→import { Message } from 'element-ui'
 3→import _, { cloneDeep, throttle } from 'lodash'
 4→
 5→import { ErrorCode } from '@/apis/ErrorCode'
 6→import i18n from '@/i18n'
 7→import router from '@/router'
 8→import store from '@/store'
 9→import { defaultUserInfoData } from '@/store/state'
10→import { deviceType } from '@/utils'
11→
12→const logoutCode = new Set([
13→    ErrorCode.USER_LOGIN_TIMEOUT0,
14→    ErrorCode.USER_LOGIN_TIMEOUT1,
15→    ErrorCode.USER_NEED_LOGIN,
16→])
17→const needUpdateCode = new Set([ErrorCode.CLIENT_OUT_OF_DATE])
18→const successCode = new Set([ErrorCode.NO_ERROR])
19→
20→const updateMessage = _.throttle(() => {
21→    Message.warning(i18n.t('axios2_296'))
22→}, 10000)
23→export default function <P = any, R = any>(
24→    url: string,
25→    method: 'get' | 'post',
26→    param: P = {},
27→    errorMessage?: string | 'auto'
28→): Promise<R> {
29→    param.sys_lang = store.state.curSysLang === 'en' ? 'en' : 'zh_CN'
30→    param.sys_site =
31→        param.sys_site ||
32→        // 当前页为管理端，自动添加参数当前办公室
33→        (store.state.currentPage === 'admin' ? store.state.currSite : undefined)
34→    param.version_info = PRODUCTION ? VERSION_INFO : undefined
35→    const options = {
36→        method,
37→        url,
38→        data: undefined,
39→        withCredentials: true,
40→        params: undefined,
41→    }
42→    method === 'get' ? (options.params = param) : (options.data = param)
43→    return new Promise((resolve, reject) => {
44→        axios(options)
45→            .then(rsp => {
46→                if (successCode.has(rsp.data.error_code) || needUpdateCode.has(rsp.data.error_code)) {
47→                    if (
48→                        needUpdateCode.has(rsp.data.error_code) ||
49→                        (param.sys_aggregate &&
50→                            Object.values(rsp.data).some((item: Record<string, any>) =>
51→                                ['0', '450003'].includes(item.error_code)
52→                            ))
53→                    ) {
54→                        updateMessage()
55→                    }
56→                    resolve(rsp.data.data)
57→                } else if (logoutCode.has(rsp.data.error_code)) {
58→                    if (!router.currentRoute.meta?.noLogin) {
59→                        // 清除缓存数据
60→                        store.commit('setUserInfo', cloneDeep(defaultUserInfoData))
61→                        store.commit('setAdminMenu', false)
62→                        if (deviceType.isKnock) {
63→                            router.push('/login-help')
64→                        } else {
65→                            router.push('/login-pwd')
66→                        }
67→                    }
68→                    if (errorMessage === 'auto') {
69→                        Message.error(rsp.data.error_msg || (i18n.t('serverException') as string))
70→                    } else if (errorMessage) {
71→                        Message.error(errorMessage)
72→                    }
73→                    reject(rsp.data)
74→                } else {
75→                    reject(rsp.data)
76→                    if (errorMessage === 'auto') {
77→                        Message.error(rsp.data.error_msg || (i18n.t('serverException') as string))
78→                    } else if (errorMessage) {
79→                        Message.error(errorMessage)
80→                    }
81→                }
82→            })
83→            .catch(err => {
84→                reject(err)
85→                if (errorMessage === 'auto') {
86→                    Message.error(i18n.t('serverException') as string)
87→                } else if (errorMessage) {
88→                    Message.error(errorMessage)
89→                }
90→            })
91→    })
92→}
