 89→    /**
 90→     * 按配置生成授权 token。
 91→     *
 92→     * @param array $conf 配置信息
 93→     * @throws \App\Exceptions\CommonException
 94→     * @throws \App\Exceptions\ServerException redis 交互错误
 95→     * @throws \App\Exceptions\AuthorizationException 授权失败
