 97→     */
 98→    public function generateToken(array $conf): string
 99→    {
100→        // 检查是否缺少了必要的 key
101→        if (!array_has_all_keys($conf, $this->requiredColumns)) {
102→            throw new AuthorizationException('missing required columns', AuthorizationException::ERR_AUTHORIZE_MISSING_REQUIRED_FIELDS);
103→        }
104→
105→        // 检查 res_type 是否有误
106→        $resConf = ResourceService::app()->getResConf($conf['res_type']);
107→        if (empty($resConf)) {
108→            throw new ServerException('wrong configuration for resource type', ServerException::ERR_SERVER_CONFIG);
109→        }
110→
111→        // 检查传递过来的 sfusers 的合法性，这里做个兼容，既可以按照 sfuser_id 授权，也可以按照 sfuser 的 nickname 授权
112→        if (!empty($conf['sfusers'])) {
113→            $sfusers = $conf['sfusers'];
114→            // 传递的是数组，对数组中的每个值逐一到 Redis 中检查
115→            if (is_array($conf['sfusers'])) {
116→                $authorizedUserIds = [];
117→                $first = $sfusers[0];
118→                if (is_int($first)) {
119→                    $indexKey = 'id';
120→                } else {
121→                    $indexKey = 'nickname';
122→                }
123→                foreach ($sfusers as $sfuser) {
124→                    // 查找失败会抛出一个异常，查找成功时记住对应的 sfuser_id
125→                    try {
126→                        $sfuserModel = SfuserMd::find($sfuser, $indexKey);
127→                        $authorizedUserIds[] = $sfuserModel->id;
128→                    } catch (Exception) {
129→                        // 转换为 AuthorizationException 抛出
130→                        // throw new AuthorizationException('cannot find sfuser', AuthorizationException::ERR_AUTHORIZE_NO_USER);
131→                        continue;
132→                        // 找不到被授权人时静默跳过，不再报错，后续可能离职员工中心服务器会彻底删除
133→                        // 跳过可以避免 sfuser 本人作为被授权人时不会抛出一个错误，先在这里整体兜住，业务层需要做更好的处理
134→                    }
135→                }
136→
137→                // 将配置中的 sfusers 设置为存在的 sfuser_ids
138→                $conf['sfusers'] = $authorizedUserIds;
139→            } else {
140→                // sfusers 为 anonymous 时要求被授权物只能有一个
141→                if ($conf['sfusers'] === 'anonymous') {
142→                    if (!is_array($conf['items']) || count($conf['items']) > 1) {
143→                        throw new AuthorizationException('mismatch rules of anonymous', CommonException::ERR_COMMON_INVALID_ARGUMENTS);
144→                    }
145→                } else {
146→                    throw new AuthorizationException('cannot detect sfusers', CommonException::ERR_COMMON_INVALID_ARGUMENTS);
147→                }
148→            }
149→        }
150→
151→        // 检查 emails 中的邮箱格式
152→        if (!empty($conf['emails'])) {
153→            foreach ($conf['emails'] as $one) {
154→                if (filter_var($one, FILTER_VALIDATE_EMAIL) === false) {
155→                    throw new AuthorizationException('wrong email format given', ExceptionCode::ERR_COMMON_INVALID_ARGUMENTS);
156→                }
157→            }
158→        }
159→
160→        // 当前 session 中的用户为授权人
161→        // @codeCoverageIgnoreStart
162→        try {
163→            $conf['author'] = ResourceService::app()->getOwnerIdByRule($conf['res_type']);
164→        } catch (Exception) {
165→            throw new AuthorizationException('failed to get owner id by rule');
166→        }
167→        // @codeCoverageIgnoreEnd
168→
169→        // 检查授权人是否有“被授权物”的权限
170→        try {
171→            ResourceService::app()->batchCheckUserPermission($conf['res_type'], $conf['items'], $conf['author']);
172→        } catch (Exception $e) {
173→            info('check user permission failed', ['e' => $e->getMessage()]);
174→            throw new AuthorizationException('batch check user permission failed');
175→        }
176→
177→        // 检查 operations 是否合法
178→        $invalid = array_diff($conf['operations'], $this->operations);
179→        if (!empty($invalid)) {
180→            throw new AuthorizationException('wrong operations: '.json_encode($invalid));
181→        }
182→
183→        // 检查 expire_time 是否合法
184→        if (!is_int($conf['expire_time']) || $conf['expire_time'] <= 0) {
185→            throw new AuthorizationException('wrong expire_time: '.$conf['expire_time']);
186→        }
187→
188→        $tokenMd = TokenMd::create($conf);
189→
190→        // 针对某些资源的类型，我们建立一个反向的 map
191→        if (
192→            in_array($tokenMd->authInfo['res_type'], config('my_project.allowed_decrypt_via_tokens_when_search_resources', []))
193→            && !empty($tokenMd->authInfo['sfusers'])
194→        ) {
195→            // 追加授权人，这边失效了在尝试鉴权时会自行移除掉
196→            foreach ($tokenMd->authInfo['items'] as $item) {
197→                $this->addTokens2Map($tokenMd->authInfo['res_type'], $item, $tokenMd->token);
