55→    /**
56→     * 新建一个授权令牌，存入 Redis。
57→     *
58→     * @param array $authInfo 授权信息
59→     * @throws \App\Exceptions\ServerException redis 交互报错
60→     * @throws \App\Exceptions\CommonException expire_time 非法

 60→     * @throws \App\Exceptions\CommonException expire_time 非法
 61→     * @return \App\Models\TokenMd 创建好的 TokenMd
 62→     */
 63→    public static function create(array $authInfo): TokenMd
 64→    {
