 70→    /**
 71→     * 创建或更新 Token 时将授权信息写入 Redis。
 72→     *
 73→     * @throws \App\Exceptions\ServerException redis 交互报错
 74→     * @throws \App\Exceptions\CommonException expire_time 非法
 75→     * @return bool 操作成功返回 true，失败会抛出异常
 76→     */
 77→    public function save(): bool
 78→    {
 79→        $authStr = json_encode($this->authInfo);
 80→        if (empty($this->token)) {
 81→            $this->token = md5($authStr).(int)(microtime(true) * 1000000);
 82→        }
 83→
 84→        if ($this->authInfo['expire_time'] <= 0) {
 85→            throw new CommonException('expire_time invalid: '.$this->authInfo['expire_time'], CommonException::ERR_COMMON_INVALID_ARGUMENTS);
 86→        }
 87→
 88→        $redisKey = static::$redisKeyPrefix.$this->token;
 89→        $result = redis()->setex($redisKey, $this->authInfo['expire_time'], $authStr);
 90→        if (!$result) {
 91→            throw new ServerException("redis set failed: key {$redisKey}, result {$result}");
 92→        }
 93→
 94→        return true;
 95→    }
 96→
 97→    /**
 98→     * 根据令牌查询授权信息。
 99→     *
100→     * @param string $token 给定的 token
101→     * @return null|\App\Models\TokenMd 令牌过期返回 null
102→     */
103→    public static function find(string $token): ?TokenMd
104→    {
105→        $redisKey = static::$redisKeyPrefix.$token;
106→        $authStr = redis()->get($redisKey);
107→        if (empty($authStr)) {
108→            return null;
109→        }
110→
111→        $authInfo = json_decode($authStr, true);
112→        return new TokenMd($authInfo, $token);
113→    }
